10	extension Array where Array.Element == UInt8 {
11	
12	    func toBinaryInteger<T: FixedWidthInteger>(start: Int) -> T {
13	        var collectedBytes: [Element] = []
14	
15	        let length = T.bitWidth / 8
16	
17	        for index in start..<start + length where index < count {
18	            collectedBytes.append(self[index])
19	        }
20	
21	        return collectedBytes.withUnsafeBytes { pointer in
22	            UnsafeRawPointer(pointer.baseAddress!).load(as: T.self)
23	        }
24	    }
25	    
26	    func toFloat(start: Int) -> Float32 {
27	        var bytes: [UInt8] = []
28	        let floatSize = 4
29	
30	        for index in start..<start + floatSize where index < count {
31	            bytes.append(self[index])
32	        }
33	        var floatValue: Float32 = 0.0
34	        memcpy(&floatValue, bytes, floatSize)
35	        
36	        return floatValue
37	    }
38	}
