58	extension Array where Element: Hashable {
59	    func difference(from other: [Element]) -> [Element] {
60	        let thisSet = Set(self)
61	        let otherSet = Set(other)
62	        return Array(thisSet.symmetricDifference(otherSet))
63	    }
64	}
65	
66	extension Array where Element: Equatable {
67	    subscript(safe bounds: Range<Int>) -> ArraySlice<Element> {
68	        if bounds.lowerBound > count { return [] }
69	        let lower = Swift.max(0, bounds.lowerBound)
70	        let upper = Swift.max(0, Swift.min(count, bounds.upperBound))
71	        return self[lower..<upper]
72	    }
73	}
